import torch
from torch.autograd import Function

class ClampedReLU(Function):
    """ReLU clamped at 6 (used in MobileNet). Custom backward for illustration."""

    @staticmethod
    def forward(ctx, x, max_val=6.0):
        ctx.save_for_backward(x)
        ctx.max_val = max_val
        return x.clamp(min=0, max=max_val)

    @staticmethod
    def backward(ctx, grad_output):
        x, = ctx.saved_tensors
        # Gradient is 1 where 0 < x < max_val, else 0
        mask = (x > 0) & (x < ctx.max_val)
        return grad_output * mask.float(), None  # None for max_val (not a tensor)

# Usage
x = torch.randn(4, requires_grad=True)
y = ClampedReLU.apply(x)
loss = y.sum()
loss.backward()
print(f"x:    {x.data}")
print(f"y:    {y.data}")
print(f"grad: {x.grad}")  # 1.0 where 0 < x < 6, else 0
